const raw = ($input.first().json.stdout || '{}').toString().trim();
let data;
try { data = JSON.parse(raw); } catch (e) { data = { checks: {} }; }
const checks = data.checks || {};

// Human-friendly labels. Keys must match what check_services.sh emits.
const labels = {
  nginx: 'nginx',
  mariadb: 'MariaDB',
  n8n: 'n8n (Docker)',
  web_main: 'example.com',
  web_app: 'n8n.example.com'
};

const failed = Object.keys(checks).filter(k => !String(checks[k]).startsWith('OK'));

const store = $getWorkflowStaticData('global');
const prev = store.vg_failed || [];

const newlyFailed = failed.filter(k => !prev.includes(k));
const recovered = prev.filter(k => !failed.includes(k));
store.vg_failed = failed;

// Only notify when state changes (something goes down or recovers)
if (newlyFailed.length === 0 && recovered.length === 0) {
  return [];
}

const lines = [];
if (newlyFailed.length) {
  lines.push('\uD83D\uDD34 *VertiGuard \u2014 incident*');
  newlyFailed.forEach(k => lines.push('\u2022 ' + (labels[k] || k) + ': ' + checks[k]));
}
if (recovered.length) {
  if (lines.length) lines.push('');
  lines.push('\uD83D\uDFE2 *VertiGuard \u2014 recovered*');
  recovered.forEach(k => lines.push('\u2022 ' + (labels[k] || k) + ': OK'));
}
lines.push('');
lines.push('\uD83D\uDD52 ' + (data.ts || new Date().toISOString()));

return [{ json: { message: lines.join('\n'), failed, checks } }];
